// Horloge
unicolored.directive( 'horloge', [ '$interval', 'dateFilter', function( $interval, dateFilter ) {
    function link( scope, element, attrs ) {
        var timeoutId;

        function updateTime() {
            element.find( 'span.padd' ).html( '<time id="date_heure">' + dateFilter( new Date(), 'HH:mm:ss' ) + '</time>' );
        }
        element.on( '$destroy', function() {
            $interval.cancel( timeoutId );
        } );
        timeoutId = $interval( function() {
            updateTime(); // update DOM
        }, 1000 );
    }
    return {
        link: link
    }
} ] );
// Le menu qui apparaît au clic sur l'horloge(H:i:s)
unicolored.directive( 'menuHorloge', function() {
    return {
        restrict: "A",
        templateUrl: "/wp-content/themes/rock-unicolored/js/navbot/menu-horloge.html",
        link: function( scope, element, attrs ) {
            function dateseule() {
                // Création de la date
                date = new Date();
                annee = date.getFullYear();
                moi = date.getMonth();
                mois = new Array( 'Janvier', 'Février', 'Mars', 'Avril', 'Mai', 'Juin', 'Juillet', 'Août', 'Septembre', 'Octobre', 'Novembre', 'Décembre' );
                j = date.getDate();
                jour = date.getDay();
                jours = new Array( 'Dimanche', 'Lundi', 'Mardi', 'Mercredi', 'Jeudi', 'Vendredi', 'Samedi' );
                return jours[ jour ] + ' ' + j + ' ' + mois[ moi ] + ' ' + annee;
            }
            scope.date = dateseule();
            element.find( '.horlogemenu' ).prepend( $( '<div class="agenda">' ).datepicker() );
            $( '.agenda' ).datepicker( "option", "showWeek", true );
            $( '.agenda' ).datepicker( "option", "firstDay", 1 );
            //datepicker.setDefaults( datepicker.regional[ 'fr' ] );
            $( '.agenda' ).datepicker( "option", $.datepicker.regional[ "fr" ] );
        }
    };
} );
 
//####dev/js/tmp/angular/portfolio.js
unicolored.directive( 'imagePortfolio', function() {
    /*//////////// PORTFOLIO : affichage des images */
    return {
        restrict: "A",
        link: function( scope, element, attrs ) {
            console.log( element );
            var imageId = attrs.imagePortfolio;
            $permalink = $( '<a itemprop="thumbnailUrl" class="image text-center" href="' + attrs.url + '">' );
            //nbimg++;
            var cdn = imageId % 2 === 0 ? 'cdn1' : 'cdn2';
            $result = $permalink.html( $( '<img src="https://' + cdn + '.unicolored.com' + attrs.imageurl + '" class="img-responsive" width="344" height="224" alt="Portfolio graphic & web design Paris">' ).hide() );
            $( 'article#post-' + imageId + ' .portfolio-thumbnail' ).html( $result );
            //} );
            var i = 1;
            $( 'a.image img' ).each( function() {
                var delai = 20 * i;
                $( this ).delay( delai ).fadeIn( 500 );
                i = i + 1;
            } );
        }
    };
} );
 
//####dev/js/scripts/script_nicescroll.js
jQuery( document ).ready( function( $ ) {
    'use strict'; // Définition indispensable dans tout document javascript
    $( "html" ).niceScroll( {
        cursorcolor: "#E23134", // change cursor color in hex
        cursoropacitymin: 0, // change opacity when cursor is inactive (scrollabar "hidden" state), range from 1 to 0
        cursoropacitymax: 1, // change opacity when cursor is active (scrollabar "visible" state), range from 1 to 0
        cursorwidth: 5, // cursor width in pixel (you can also write "5px")
        cursorborder: "1px solid #E23134", // css definition for cursor border
        cursorborderradius: "2px", // border radius in pixel for cursor
        zindex: 1000, // change z-index for scrollbar div
        scrollspeed: 60, // scrolling speed
        mousescrollstep: 40, // scrolling speed with mouse wheel (pixel)
        touchbehavior: false, // enable cursor-drag scrolling like touch devices in desktop computer
        hwacceleration: true, // use hardware accelerated scroll when supported
        boxzoom: false, // enable zoom for box content
        dblclickzoom: true, // (only when boxzoom=true) zoom activated when double click on box
        gesturezoom: true, // (only when boxzoom=true and with touch devices) zoom activated when pinch out/in on box
        grabcursorenabled: true, // (only when touchbehavior=true) display "grab" icon
        autohidemode: true, // how hide the scrollbar works, possible values: true, "cursor" (only cursor hidden), false (do not hide),
        //background: "", // change css for rail background
        iframeautoresize: true, // autoresize iframe on load event
        cursorminheight: 20, // set the minimum cursor height (pixel)
        preservenativescrolling: true, // you can scroll native scrollable areas with mouse, bubbling mouse wheel event
        railoffset: false, // you can add offset top/left for rail position
        bouncescroll: false, // (only hw accell) enable scroll bouncing at the end of content as mobile-like
        spacebarenabled: true, // enable page down scrolling when space bar has pressed
        railpadding: {
            top: 0,
            right: 0,
            left: 0,
            bottom: 0
        }, // set padding for rail bar
        disableoutline: true, // for chrome browser, disable outline (orange highlight) when selecting a div with nicescroll
        horizrailenabled: true, // nicescroll can manage horizontal scroll
        railalign: 'right', // alignment of vertical rail
        //railvalign: bottom, // alignment of horizontal rail
        enabletranslate3d: true, // nicescroll can use css translate to scroll content
        enablemousewheel: true, // nicescroll can manage mouse wheel events
        enablekeyboard: true, // nicescroll can manage keyboard events
        smoothscroll: true, // scroll with ease movement
        sensitiverail: true, // click on rail make a scroll
        enablemouselockapi: true, // can use mouse caption lock API (same issue on object dragging)
        cursorfixedheight: false, // set fixed height for cursor in pixel
        hidecursordelay: 400, // set the delay in microseconds to fading out scrollbars
        directionlockdeadzone: 6, // dead zone in pixels for direction lock activation
        nativeparentscrolling: true, // detect bottom of content and let parent to scroll, as native scroll does
        enablescrollonselection: true, // enable auto-scrolling of content when selection text
        rtlmode: false, // horizontal div scrolling starts at left side
        cursordragontouch: false, // drag cursor in touch / touchbehavior mode also
        oneaxismousemode: "auto", // it permits horizontal scrolling with mousewheel on horizontal only content, if false (vertical-only) mousewheel don't scroll horizontally, if value is auto detects two-axis mouse
        //scriptpath: "" // define custom path for boxmode icons ("" => same script path)
    } );
} );
 
